import requests
import json

def get_unauthenticated_access(url):
    try:
        response = requests.get(url)
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        print(f"Error: {e}")
        return None

if __name__ == "__main__":
    # Replace with the actual URL of the facility
    facility_url = "http://example.com/facility_api"
    access_data = get_unauthenticated_access(facility_url)
    if access_data:
        print("Successfully obtained unauthenticated access data:")
        print(json.dumps(access_data, indent=4))
    else:
        print("Failed to obtain unauthenticated access.")
